# Calc Engine

import math

def add(a, b):
    return a + b

def fib(n):
    a, b = 0, 1
    out = []
    for _ in range(n):
        out.append(a)
        a, b = b, a + b
    return out

def integrate_trap(f, a, b, n=1000):
    h = (b - a) / n
    return 0.5 * h * (f(a) + 2 * sum(f(a + i * h) for i in range(1, n)) + f(b))
